#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <ctime>

struct SaveData {
    std::string playerName;
    int health;
    int attack;
    int defense;
    int level;
    double experience;
    std::vector<std::string> inventory;
    std::string timestamp;
};

void saveGame(const SaveData& data, const std::string& filename) {
    std::ofstream file(filename);

    if (!file.is_open()) {
        std::cout << "❌ Failed to save game!" << std::endl;
        return;
    }

    // Write header
    file << "=== SAVE GAME ===" << std::endl;
    file << "Saved: " << data.timestamp << std::endl;

    // Write player data
    file << "[Player]" << std::endl;
    file << "Name=" << data.playerName << std::endl;
    file << "Health=" << data.health << std::endl;
    file << "Attack=" << data.attack << std::endl;
    file << "Defense=" << data.defense << std::endl;
    file << "Level=" << data.level << std::endl;
    file << "Experience=" << data.experience << std::endl;

    // Write inventory
    file << "[Inventory]" << std::endl;
    for (const auto& item : data.inventory) {
        file << item << std::endl;
    }

    file << "=== END SAVE ===" << std::endl;

    file.close();
    std::cout << "✅ Game saved to " << filename << std::endl;
}

// Function to save high scores
void saveHighScores(const std::vector<std::pair<std::string, int>>& scores, 
                    const std::string& filename) {
    std::ofstream file(filename);

    if (!file.is_open()) {
        std::cout << "❌ Failed to save high scores!" << std::endl;
        return;
    }

    for (const auto& score : scores) {
        file << score.first << " " << score.second << std::endl;
    }

    file.close();
    std::cout << "✅ High scores saved to " << filename << std::endl;
}

int main() {
    std::cout << "=== Writing Files — Saving Game State ===" << std::endl;

    // 1. Create save data
    SaveData save;
    save.playerName = "Hero";
    save.health = 85;
    save.attack = 22;
    save.defense = 16;
    save.level = 3;
    save.experience = 150.5;
    save.inventory = {"Sword", "Shield", "Potion", "Key"};

    // Get current time
    std::time_t now = std::time(nullptr);
    save.timestamp = std::ctime(&now);
    save.timestamp.pop_back();  // Remove newline

    // 2. Save game
    saveGame(save, "savegame.txt");

    // 3. Save high scores
    std::vector<std::pair<std::string, int>> highScores = {
        {"Hero", 1200},
        {"Aragorn", 950},
        {"Gandalf", 850},
        {"Legolas", 700}
    };

    saveHighScores(highScores, "highscores.txt");

    // 4. Save config
    std::cout << "\n--- Save Config ---" << std::endl;
    std::ofstream config("config.txt");
    if (config.is_open()) {
        config << "[Settings]" << std::endl;
        config << "Difficulty=Normal" << std::endl;
        config << "SoundEnabled=true" << std::endl;
        config << "Fullscreen=false" << std::endl;
        config << "Volume=75" << std::endl;
        config.close();
        std::cout << "✅ Config saved!" << std::endl;
    }

    // 5. Show saved files
    std::cout << "\n--- Saved Files ---" << std::endl;
    std::cout << "✅ savegame.txt — main save" << std::endl;
    std::cout << "✅ highscores.txt — leaderboard" << std::endl;
    std::cout << "✅ config.txt — settings" << std::endl;

    std::cout << "\n--- Writing Methods ---" << std::endl;
    std::cout << "✅ << operator — formatted output" << std::endl;
    std::cout << "✅ std::endl — newline" << std::endl;
    std::cout << "✅ Custom format — readable saves" << std::endl;

    return 0;
}

