#include <iostream>
#include <fstream>
#include <string>

struct Player {
    std::string name;
    int health;
    int attack;
    int defense;
    int level;
};

int main() {
    Player hero = {"Hero", 100, 20, 15, 5};

    std::cout << "=== Saving Player Data ===" << std::endl;

    // Human-readable format
    std::ofstream readable("player_readable.txt");
    if (readable.is_open()) {
        readable << "Player Name: " << hero.name << std::endl;
        readable << "Health: " << hero.health << std::endl;
        readable << "Attack: " << hero.attack << std::endl;
        readable << "Defense: " << hero.defense << std::endl;
        readable << "Level: " << hero.level << std::endl;
        readable.close();
        std::cout << "✅ Human-readable save: player_readable.txt" << std::endl;
    }

    // Compact format
    std::ofstream compact("player_compact.txt");
    if (compact.is_open()) {
        compact << hero.name << " " 
                << hero.health << " " 
                << hero.attack << " " 
                << hero.defense << " " 
                << hero.level << std::endl;
        compact.close();
        std::cout << "✅ Compact save: player_compact.txt" << std::endl;
    }

    std::cout << "\n✅ Player saved successfully!" << std::endl;

    return 0;
}
